import React from "react";
import { GoogleMap, LoadScript } from "@react-google-maps/api";

const containerStyle = {
  width: "100%",
  height: "400px"
};

const center = {
  lat: 25.5941,
  lng: 85.1376
};

function Map() {

  return (

    <LoadScript googleMapsApiKey="YOUR_REAL_API_KEY">

      <GoogleMap
        mapContainerStyle={containerStyle}
        center={center}
        zoom={12}
      />

    </LoadScript>

  )

}

export default Map;
